class EventBus {
  constructor() { this.listeners = {}; }
  on(evt, fn) {
    this.listeners[evt] = this.listeners[evt] || [];
    this.listeners[evt].push(fn);
  }
  emit(evt, payload) {
    for (const fn of this.listeners[evt]) fn(payload);
  }
}
